const data = $input.first().json;
const topPosts = data.top_posts || [];
const insights = data.insights || [];
const posts = data.generated_posts || [];
const generatedAt = new Date().toISOString();

return posts.map((post, index) => {
  const sourcePost = topPosts[index % Math.max(topPosts.length, 1)] || {};

  return {
    json: {
      generated_at: generatedAt,
      source_profile: data.source_profile,
      total_posts_analyzed: data.total_posts_found,
      source_top_post_rank: sourcePost.rank ?? '',
      source_top_post_text: sourcePost.text ?? '',
      source_top_post_impressions: sourcePost.impressions ?? '',
      source_top_post_reactions: sourcePost.reactions ?? '',
      source_top_post_comments: sourcePost.comments ?? '',
      source_top_post_reposts: sourcePost.reposts ?? '',
      insight_1: insights[0] ?? '',
      insight_2: insights[1] ?? '',
      insight_3: insights[2] ?? '',
      insight_4: insights[3] ?? '',
      new_post_number: index + 1,
      new_post_title: post.title ?? '',
      new_post_hook: post.hook ?? '',
      new_post_text: post.post_text ?? '',
      new_post_cta: post.cta ?? '',
      format_type: post.format_type ?? '',
      why_it_should_work: post.why_it_should_work ?? ''
    }
  };
});

const response = $json;

const rawText = response?.output?.[0]?.content?.[0]?.text ?? response?.output_text ?? '';

if (!rawText) {
  throw new Error('No usable text found in the OpenAI response.');
}

let parsed;
try {
  parsed = JSON.parse(rawText);
} catch (error) {
  throw new Error(`OpenAI JSON could not be parsed: ${error.message}\n\nRaw response:\n${rawText}`);
}

const source = $('Normalize + Rank LinkedIn Posts').first().json;

return [
  {
    json: {
      source_profile: source.source_profile,
      total_posts_found: source.total_posts_found,
      top_posts: source.top_posts,
      insights: parsed.insights,
      generated_posts: parsed.posts,
      generated_count: parsed.posts.length
    }
  }
];

