={{ {
  model: 'gpt-5.4-mini',
  input: [
    {
      role: 'system',
      content: 'You are a LinkedIn content strategist and copywriter. Analyze top-performing LinkedIn posts, extract useful patterns, and create original post ideas that fit the platform. Return only valid JSON matching the required schema.'
    },
    {
      role: 'user',
      content: $json.analysis_prompt
    }
  ],
  text: {
    format: {
      type: 'json_schema',
      name: 'linkedin_content_engine_output',
      strict: true,
      schema: {
        type: 'object',
        properties: {
          insights: {
            type: 'array',
            minItems: 3,
            maxItems: 10,
            items: { type: 'string' }
          },
          posts: {
            type: 'array',
            minItems: 7,
            maxItems: 7,
            items: {
              type: 'object',
              properties: {
                title: { type: 'string' },
                hook: { type: 'string' },
                post_text: { type: 'string' },
                cta: { type: 'string' },
                format_type: { type: 'string' },
                why_it_should_work: { type: 'string' }
              },
              required: ['title', 'hook', 'post_text', 'cta', 'format_type', 'why_it_should_work'],
              additionalProperties: false
            }
          }
        },
        required: ['insights', 'posts'],
        additionalProperties: false
      }
    }
  }
} }}

parameters.jsCode:
const items = $input.all();

const posts = items
  .map((item, index) => {
    const p = item.json;

    const text = (
      p.text ??
      p.postText ??
      p.content ??
      p.caption ??
      p.description ??
      p.fullText ??
      p.body ??
      p.linkedinText ??
      p.postContent ??
      ''
    ).toString().trim();

    const impressions = Number(
      p.impressions ??
      p.impressionCount ??
      p.metrics?.impressions ??
      p.statistics?.impressions ??
      p.analytics?.impressions ??
      p.views ??
      p.viewCount ??
      p.engagementStats?.impressions ??
      0
    );

    const reactions = Number(
      p.reactions ??
      p.reactionCount ??
      p.likes ??
      p.likeCount ??
      p.metrics?.reactions ??
      p.statistics?.reactions ??
      0
    );

    const comments = Number(
      p.comments ??
      p.commentCount ??
      p.metrics?.comments ??
      p.statistics?.comments ??
      0
    );

    const reposts = Number(
      p.reposts ??
      p.shares ??
      p.shareCount ??
      p.metrics?.shares ??
      p.statistics?.shares ??
      0
    );

    return {
      rank: 0,
      id: p.id ?? p.postId ?? p.urn ?? `post_${index + 1}`,
      text,
      impressions,
      reactions,
      comments,
      reposts,
      post_url: p.url ?? p.postUrl ?? p.linkedinUrl ?? '',
      published_at: p.publishedAt ?? p.createdAt ?? p.timestamp ?? '',
      raw: p
    };
  })
  .filter((post) => post.text && !Number.isNaN(post.impressions));

if (!posts.length) {
  throw new Error('No LinkedIn posts with usable text and impression data were found in the Apify response.');
}

posts.sort((a, b) => b.impressions - a.impressions);
posts.forEach((post, index) => {
  post.rank = index + 1;
});

const topPosts = posts.slice(0, Math.min(5, posts.length));

const summaryForPrompt = topPosts.map((post) => ({
  rank: post.rank,
  id: post.id,
  impressions: post.impressions,
  reactions: post.reactions,
  comments: post.comments,
  reposts: post.reposts,
  text: post.text
}));

const analysisPrompt = `Analyze the following top-performing LinkedIn posts ranked by impressions.\n\nTop posts:\n${JSON.stringify(summaryForPrompt, null, 2)}\n\nTasks:\n1. Identify patterns in hooks, tone, structure, readability, CTA style, formatting, topic angle, and repeated language choices.\n2. Summarize the most important success factors.\n3. Write 7 completely new LinkedIn posts inspired by these patterns, but do not copy phrasing or structure too closely.\n4. Write in natural, polished English for a professional audience.\n5. Make the posts feel native to LinkedIn: strong opening line, short readable paragraphs, clear idea progression, and thoughtful closing line.\n6. Avoid filler, generic motivation, and repeated wording.\n7. Return only JSON matching the schema.`;

return [
  {
    json: {
      source_profile: $('Validate Config + Build Actor Input').first().json.linkedin_profile_url,
      total_posts_found: posts.length,
      top_posts: topPosts,
      summary_for_prompt: summaryForPrompt,
      analysis_prompt: analysisPrompt
    }
  }
];

const config = $input.first().json;

const requiredFields = ['apify_token', 'apify_actor_id', 'openai_api_key', 'linkedin_profile_url'];
const missing = requiredFields.filter((field) => {
  const value = config[field];
  return value === undefined || value === null || value === '' || String(value).startsWith('replace_with_your_');
});

if (missing.length) {
  throw new Error(`Missing required configuration fields: ${missing.join(', ')}`);
}

return [
  {
    json: {
      ...config,
      actor_input: {
        profileUrls: [config.linkedin_profile_url],
        resultsLimit: Number(config.results_limit || 20)
      }
    }
  }
];
